UseTemplate.ON_AFTER_SET_CODE:
p0 (A:ELECTRICAL MASTER BATTERY:2, Bool) != if{
	p0 (>K:BATTERY2_SET)
}

p0 (A:ELECTRICAL MASTER BATTERY:3, Bool) != if{
	p0 (>K:BATTERY3_SET)
}

p0 (A:RECIP ENG LEFT MAGNETO:1, Bool) != if{
	(>K:MAGNETO1_LEFT)
}
p0 (A:RECIP ENG RIGHT MAGNETO:1, Bool) != if{
	(>K:MAGNETO1_RIGHT)
}

p0 (A:RECIP ENG LEFT MAGNETO:2, Bool) != if{
	(>K:MAGNETO2_LEFT)
}
p0 (A:RECIP ENG RIGHT MAGNETO:2, Bool) != if{
	(>K:MAGNETO2_RIGHT)
}

Component.Update:
(A:AUTOPILOT MASTER, bool) (A:DELTA HEADING RATE, degrees per second) s0 abs 3 > and if{
	l0 sign 3 * (>A:DELTA HEADING RATE, degrees per second)
}

UseTemplate.UPDATE_CODE:
(O:INIT) ! if{
	#INIT_VAL# (>L:FSS_P2012_WRITEVAR_RECIP_ENG_WATE_GATE_POSITION_1)
	#INIT_VAL# (>L:FSS_P2012_WRITEVAR_RECIP_ENG_WATE_GATE_POSITION_2)
	#INIT_VAL# (>L:FSS_P2012_WRITEVAR_PROP_BETA_FORCED_ACTIVE_1)
	#INIT_VAL# (>L:FSS_P2012_WRITEVAR_PROP_BETA_FORCED_ACTIVE_2)
	#INIT_VAL# (>L:FSS_P2012_WRITEVAR_PROP_BETA_FORCED_POSITION_1)
	#INIT_VAL# (>L:FSS_P2012_WRITEVAR_PROP_BETA_FORCED_POSITION_2)
	1 (>O:INIT)
} els{
	#INIT_VAL# (L:FSS_P2012_WRITEVAR_RECIP_ENG_WATE_GATE_POSITION_1) s0 != if{
		l0 (>A:RECIP ENG WASTEGATE POSITION:1, percent)
	}
	#INIT_VAL# (L:FSS_P2012_WRITEVAR_RECIP_ENG_WATE_GATE_POSITION_2) s0 != if{
		l0 (>A:RECIP ENG WASTEGATE POSITION:2, percent)
	}
	#INIT_VAL# (L:FSS_P2012_WRITEVAR_PROP_BETA_FORCED_ACTIVE_1) s0 != if{
		l0 (>A:PROP BETA FORCED ACTIVE:1, Bool)
	}
	#INIT_VAL# (L:FSS_P2012_WRITEVAR_PROP_BETA_FORCED_ACTIVE_2) s0 != if{
		l0 (>A:PROP BETA FORCED ACTIVE:2, Bool)
	}
	#INIT_VAL# (L:FSS_P2012_WRITEVAR_PROP_BETA_FORCED_POSITION_1) s0 != if{
		l0 (>A:PROP BETA FORCED POSITION:1, Degree)
	}
	#INIT_VAL# (L:FSS_P2012_WRITEVAR_PROP_BETA_FORCED_POSITION_2) s0 != if{
		l0 (>A:PROP BETA FORCED POSITION:2, Degree)
	}
}

UseTemplate.TOGGLE_CODE:
(L:FSS_P2012_CABIN_SUNSHADE_VISIBLE) if{
	0 (>L:FSS_P2012_CABIN_SUNSHADE_VISIBLE)
} els{
	(A:ENG COMBUSTION:1, Bool) (A:ENG COMBUSTION:2, Bool) or ! if{
		1 (>L:FSS_P2012_CABIN_SUNSHADE_VISIBLE)
	}
}
